  const APPS = [{"title":"Contract Budget Calculator (PO)","b64":""},{"title":"New Bill Rate","b64":""},{"title":"Rafał Wilk","b64":""},{"title":"Intake Call","b64":""},{"title":"CV Match Offline","b64":"","subtitle":"Inteligentna ocena dopasowania CV do oferty pracy","tag":"REKRUTER"},{"title":"Skanowanie duplikatów","b64":""},{"title":"Merit increase 2026","b64":""},{"title":"Przegląd agencji","b64":""}];


  // UTF-8 safe Base64 decoder (prevents mojibake like "JÄ™zyk", "KoÅ„cowa")
  function b64ToUtf8(b64){
    try{
      const bin = atob(b64);
      // Prefer TextDecoder when available
      if (typeof TextDecoder !== 'undefined'){
        const bytes = Uint8Array.from(bin, c => c.charCodeAt(0));
        return new TextDecoder('utf-8').decode(bytes);
      }
      // Fallback for older engines
      return decodeURIComponent(escape(bin));
    }catch(e){
      try{ return atob(b64); }catch(e2){ return ''; }
    }
  }

  const __rwMeritApp = APPS.find(function(app){
    return app && /merit increase 2026/i.test(app.title || '');
  });
  window.__rwMeritModuleHtml = __rwMeritApp ? b64ToUtf8(__rwMeritApp.b64) : '';

  // Detect module language from its HTML (<html lang="..">) so the Home button matches the module, not the platform UI.
  function __rwDetectLangFromHtml(html){
    try{
      const m = String(html || '').match(/<html[^>]*\blang\s*=\s*["']\s*([a-zA-Z-]+)\s*["']/i);
      if (!m) return '';
      const v = (m[1] || '').toLowerCase();
      if (v.startsWith('pl')) return 'pl';
      if (v.startsWith('en')) return 'en';
      if (v.startsWith('nl')) return 'nl';
      return '';
    }catch(e){
      return '';
    }
  }

  const frame = document.getElementById('appframe');
  const placeholder = document.querySelector('.placeholder');
  const __rwActiveModuleKey = 'rw_active_module_idx';
  const __rwActiveFrameKey = 'rw_active_frame_state';
  const __rwAutosavePrefix = 'rw_module_state_v1:';

  function __rwSaveActiveModule(idx){
    try{
      localStorage.setItem(__rwActiveModuleKey, String(idx));
      localStorage.removeItem(__rwActiveFrameKey);
    }catch(e){}
  }

  function __rwSaveActiveFrame(id, title){
    try{
      localStorage.setItem(__rwActiveFrameKey, JSON.stringify({ id:String(id || ''), title:String(title || '') }));
      localStorage.removeItem(__rwActiveModuleKey);
    }catch(e){}
  }

  function __rwClearActiveModule(){
    try{
      localStorage.removeItem(__rwActiveModuleKey);
      localStorage.removeItem(__rwActiveFrameKey);
    }catch(e){}
  }

  function __rwReadActiveModule(){
    try{
      const raw = localStorage.getItem(__rwActiveModuleKey);
      if (raw === null || raw === '') return null;
      const idx = Number(raw);
      return Number.isInteger(idx) && idx >= 0 && idx < APPS.length ? idx : null;
    }catch(e){
      return null;
    }
  }

  function __rwReadActiveFrame(){
    try{
      const raw = localStorage.getItem(__rwActiveFrameKey);
      if (!raw) return null;
      const parsed = JSON.parse(raw);
      if (!parsed || !parsed.id || !document.getElementById(parsed.id)) return null;
      return parsed;
    }catch(e){
      return null;
    }
  }

  window.__rwClearActiveModule = __rwClearActiveModule;
  window.__rwSaveActiveFrame = __rwSaveActiveFrame;

  function __rwModuleStateKey(kind, id){
    return __rwAutosavePrefix + String(kind || 'module') + ':' + String(id || 'unknown');
  }

  function __rwFieldKey(el, index){
    if (!el) return 'field_' + index;
    if (el.id) return '#' + el.id;
    if (el.name) return 'name:' + el.name;
    const label = el.getAttribute('aria-label') || el.getAttribute('placeholder') || el.getAttribute('data-i18n') || '';
    const tag = (el.tagName || 'field').toLowerCase();
    const type = (el.type || '').toLowerCase();
    return tag + ':' + type + ':' + index + ':' + label;
  }

  function __rwCollectFormState(doc){
    const state = {};
    if (!doc) return state;
    const fields = Array.from(doc.querySelectorAll('input, textarea, select'));
    fields.forEach((el, index) => {
      try{
        const type = (el.type || '').toLowerCase();
        if (type === 'password' || type === 'file' || type === 'button' || type === 'submit' || type === 'reset' || el.readOnly || el.disabled || el.classList.contains('readonly')) return;
        const key = __rwFieldKey(el, index);
        if (type === 'checkbox' || type === 'radio') state[key] = { kind:type, checked:!!el.checked, value:el.value || '' };
        else state[key] = { kind:type || el.tagName.toLowerCase(), value:el.value || '' };
      }catch(e){}
    });
    return state;
  }

  function __rwRestoreFormState(doc, saved){
    if (!doc || !saved || !saved.fields) return;
    const fields = Array.from(doc.querySelectorAll('input, textarea, select'));
    fields.forEach((el, index) => {
      try{
        const type = (el.type || '').toLowerCase();
        if (type === 'password' || type === 'file' || type === 'button' || type === 'submit' || type === 'reset' || el.readOnly || el.disabled || el.classList.contains('readonly')) return;
        const item = saved.fields[__rwFieldKey(el, index)];
        if (!item) return;
        if (type === 'checkbox' || type === 'radio') el.checked = !!item.checked;
        else el.value = item.value || '';
        el.dispatchEvent(new Event('input', { bubbles:true }));
        el.dispatchEvent(new Event('change', { bubbles:true }));
      }catch(e){}
    });
  }

  function __rwSaveFrameState(iframe, stateKey){
    try{
      const doc = iframe && iframe.contentDocument;
      if (!doc || !stateKey) return;
      const payload = { savedAt:new Date().toISOString(), fields:__rwCollectFormState(doc) };
      localStorage.setItem(stateKey, JSON.stringify(payload));
    }catch(e){}
  }

  function __rwClearFrameState(stateKey){
    try{ if (stateKey) localStorage.removeItem(stateKey); }catch(e){}
  }

  function __rwAttachAutosave(iframe, kind, id){
    try{
      if (!iframe) return;
      const stateKey = __rwModuleStateKey(kind, id);
      iframe.dataset.rwAutosaveKey = stateKey;
      const doc = iframe.contentDocument;
      if (!doc || doc.__rwAutosaveAttached) return;
      doc.__rwAutosaveAttached = true;
      try{
        const saved = JSON.parse(localStorage.getItem(stateKey) || 'null');
        if (saved) setTimeout(() => __rwRestoreFormState(doc, saved), 80);
      }catch(e){}
      let timer = null;
      const schedule = () => {
        clearTimeout(timer);
        timer = setTimeout(() => __rwSaveFrameState(iframe, stateKey), 250);
      };
      doc.addEventListener('input', schedule, true);
      doc.addEventListener('change', schedule, true);
      doc.addEventListener('click', function(event){
        const target = event.target && event.target.closest ? event.target.closest('button, input[type="button"], input[type="reset"], .btn') : null;
        if (!target) return;
        const text = ((target.textContent || target.value || target.id || '') + '').toLowerCase();
        if (/wyczy|clear|reset|nieuw|new/.test(text)){
          setTimeout(function(){ __rwClearFrameState(stateKey); }, 80);
        }else{
          schedule();
        }
      }, true);
      setTimeout(() => __rwSaveFrameState(iframe, stateKey), 500);
    }catch(e){}
  }


  // Protect every platform module against accidental refresh, tab close or navigation away.
  // Modern browsers show their own confirmation text, but require returnValue to trigger it.
  window.__rwCloseGuardEnabled = true;
  window.addEventListener('beforeunload', function(event){
    if (!window.__rwCloseGuardEnabled) return;
    const hasActiveModule = document.body.classList.contains('app-open') || __rwReadActiveModule() !== null || __rwReadActiveFrame() !== null;
    if (!hasActiveModule) return;
    const message = 'Masz otwarty modul na platformie. Po odswiezeniu platforma wroci do ostatniego modulu.';
    event.preventDefault();
    event.returnValue = message;
    return message;
  });

  function loadApp(idx){
    if (!window.__rwModulePinConsume || !window.__rwModulePinConsume()){
      window.__rwRequestModulePin && window.__rwRequestModulePin(function(){ window.loadApp(idx); }, APPS[idx] && APPS[idx].title);
      return;
    }
    __rwSaveActiveModule(idx);
    // Use srcdoc to keep same-origin context (enables localStorage and in-module language switching)
    const html = b64ToUtf8(APPS[idx].b64);
    const __lang = __rwDetectLangFromHtml(html);
    frame.removeAttribute('src');
    frame.srcdoc = html;
    frame.classList.add('show');
    setTimeout(__rwPushLang, 60);

    if (placeholder) placeholder.remove();
    // Show viewport on full screen and hide grid
    const viewport = document.querySelector('.viewport');
    if (viewport) {
      viewport.classList.add('active');
      document.body.classList.add('app-open');
    }
    // Opcjonalnie zmieniamy tytuł karty przeglądarki
    document.title = 'Rafal Wilk Digital Workshop © — ' + APPS[idx].title;
    if (window.__rwSetActiveApp) window.__rwSetActiveApp(APPS[idx].title, 'appframe', __lang);
    setTimeout(function(){ __rwAttachAutosave(frame, 'module', idx); }, 140);
    setTimeout(function(){ __rwAttachAutosave(frame, 'module', idx); }, 650);
  }

  document.querySelectorAll('.btn[data-idx]').forEach(btn => btn.addEventListener('click', () => loadApp(+btn.dataset.idx)));

  // Accent ring on iframe based on app index
  const __accents = ['#3b82f6','#10b981','#f59e0b','#ef4444','#a855f7','#06b6d4'];
  const __origLoad = window.loadApp || function(idx){
    const html = b64ToUtf8(APPS[idx].b64);
    const __lang = __rwDetectLangFromHtml(html);
    frame.removeAttribute('src');
    frame.srcdoc = html;
    frame.classList.add('show');
    if (placeholder) placeholder.remove();
    document.title = 'Rafal Wilk Digital Workshop © — ' + APPS[idx].title;
    if (window.__rwSetActiveApp) window.__rwSetActiveApp(APPS[idx].title, 'appframe', __lang);
    setTimeout(function(){ __rwAttachAutosave(frame, 'module', idx); }, 140);
    setTimeout(function(){ __rwAttachAutosave(frame, 'module', idx); }, 650);
  };
  window.loadApp = function(idx){
    __rwSaveActiveModule(idx);
    __origLoad(idx);
    frame.style.boxShadow = '0 0 0 3px ' + __accents[idx % __accents.length] + ' inset, 0 0 0 1px rgba(255,255,255,.08)';
  };

  document.addEventListener('DOMContentLoaded', function(){
    const frameState = __rwReadActiveFrame();
    if (frameState){
      setTimeout(function(){
        try{ openApp(frameState.id, frameState.title || ''); }catch(e){}
      }, 0);
      return;
    }
    const idx = __rwReadActiveModule();
    if (idx === null) return;
    setTimeout(function(){
      try{ window.loadApp(idx); }catch(e){}
    }, 0);
  });
